const url = $json.Google_Drive_Document_URL || '';
// Extract file ID from Google Drive URL patterns:
// https://drive.google.com/file/d/FILE_ID/view
// https://drive.google.com/file/d/FILE_ID/view?usp=sharing
// https://drive.google.com/open?id=FILE_ID
let fileId = '';
const match1 = url.match(/\/file\/d\/([^/]+)/);
const match2 = url.match(/[?&]id=([^&]+)/);
if (match1) {
  fileId = match1[1];
} else if (match2) {
  fileId = match2[1];
}
if (!fileId) {
  throw new Error('Could not extract file ID from Google Drive URL: ' + url);
}
return [{ json: { fileId, originalUrl: url } }];

const items = $input.all();
const item = items[0];
const binaryData = item.binary;
if (!binaryData || !binaryData.data) {
  throw new Error('No binary data found from Google Drive download');
}
const binaryObj = binaryData.data;
const base64 = binaryObj.data;
const fileName = binaryObj.fileName || 'document.pdf';
const mimeType = binaryObj.mimeType || 'application/pdf';
return [{ json: { file_base64: base64, fileName, mimeType } }];

